import{_ as s,o,c as a,ah as i}from"./chunks/framework.DE8HRBTl.js";const k=JSON.parse('{"title":"组件开发 Skills","description":"","frontmatter":{},"headers":[],"relativePath":"guide/组件开发Skills.md","filePath":"guide/组件开发Skills.md"}'),d={name:"guide/组件开发Skills.md"};function c(t,e,l,n,p,r){return o(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="组件开发-skills" tabindex="-1">组件开发 Skills <a class="header-anchor" href="#组件开发-skills" aria-label="Permalink to &quot;组件开发 Skills&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Beta 状态</p><p>本「组件开发 Skills」目前处于 <strong>Beta</strong> 阶段，功能和使用方式仍在持续打磨中。试用过程中发现任何问题，或有改进建议，欢迎随时反馈到 <a href="https://github.com/xsy-neoui/neo-cmp-docs/issues" target="_blank" rel="noreferrer">neo-cmp-docs Issues</a>。</p></div><h2 id="什么是组件开发-skills" tabindex="-1">什么是组件开发 Skills <a class="header-anchor" href="#什么是组件开发-skills" aria-label="Permalink to &quot;什么是组件开发 Skills&quot;">​</a></h2><p>「组件开发 Skills」是一组面向 AI 编辑器（CodeBuddy、Kiro、Cursor等）的开发技能包，内容涵盖 Neo 自定义组件从命令行操作、React 组件开发、Vue 组件迁移 React 组件的开发指南 Skill 和开发规范，指导 AI 开发出更贴近 Neo 平台和业务需求的自定义组件。</p><p>目前提供以下五个技能包：</p><table tabindex="0"><thead><tr><th>Skill</th><th>作用</th></tr></thead><tbody><tr><td><code>neo-cmp-cli</code></td><td><code>neo</code> 命令行工具技能，负责项目创建 / 初始化、组件新增、发布 / 上传、预览、本地调试、外链调试、登录 / 登出等命令操作。遵循非交互式执行、镜像源配置、登录态预检等规范。</td></tr><tr><td><code>neo-cmp-dev</code></td><td>React 16 + TypeScript 自定义组件开发技能，覆盖组件目录结构、<code>model.ts</code> 模型、<code>propsSchema</code> 配置、事件动作（<code>@NeoEvent</code> + <code>BaseCmp</code>）、运行时上下文、平台预置组件、数据源、SCSS + BEM 样式隔离及工程规范。开发完成后可转交 <code>neo-code-review</code> 技能进行代码审查，通过后再转交 <code>neo-cmp-cli</code> 执行预览 / 发布。</td></tr><tr><td><code>neo-code-review</code></td><td>Neo 平台自定义组件代码审查与规范校验技能。对 <code>neo-cmp-dev</code> 开发的组件进行入口文件、模型文件、样式文件、事件动作声明、数据源使用方式、字段名合法性等的全面检查，输出整改清单后转交 <code>neo-cmp-dev</code> 修复，直至组件符合所有约束和规则。</td></tr><tr><td><code>vue-to-react</code></td><td>Vue 组件 / 项目迁移到 React 16 + TypeScript 的语法层技能。覆盖 SFC 拆分、模板转 JSX、响应式转 hooks、生命周期对照、通信机制、Vuex / Pinia 转 MobX、Vue Router 转 React Router、自定义指令 / mixin 转 hook / HOC 等。语法迁移完成后转交 <code>neo-cmp-dev</code> 做平台规范落地。</td></tr><tr><td><code>frontend-design</code></td><td>前端创意设计技能，打造具有高设计品质的独特界面。负责选定美学方向（极简 / 极繁 / 复古等），关注字体排版、色彩主题、动效、空间构成和背景细节，避免通用的 AI 审美。</td></tr></tbody></table><h3 id="技能协作关系" tabindex="-1">技能协作关系 <a class="header-anchor" href="#技能协作关系" aria-label="Permalink to &quot;技能协作关系&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vue-to-react (Vue → React 语法迁移)</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>neo-cmp-dev (平台规范落地)</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>neo-code-review (代码审查与规范校验，发现问题后返回 neo-cmp-dev 修复)</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>neo-cmp-cli (命令执行：创建、预览、发布)</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>frontend-design (UI/UX 创意设计，可贯穿任何阶段)</span></span></code></pre></div><h2 id="支持的-ai-编辑器" tabindex="-1">支持的 AI 编辑器 <a class="header-anchor" href="#支持的-ai-编辑器" aria-label="Permalink to &quot;支持的 AI 编辑器&quot;">​</a></h2><p><code>neo-cmp-cli</code> 会将技能包安装到对应产品的 skill 目录下，当前支持：</p><ul><li><strong>CodeBuddy</strong></li><li><strong>Kiro</strong></li><li><strong>Cursor</strong></li><li><strong>Claude Code</strong></li></ul><h2 id="安装技能包" tabindex="-1">安装技能包 <a class="header-anchor" href="#安装技能包" aria-label="Permalink to &quot;安装技能包&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">前置条件</p><p>1、安装技能包前，请确保已全局安装 <code>neo-cmp-cli</code>。如尚未安装，请参考 <a href="/neo-cmp-docs/html/guide/安装.html">安装</a> 页面完成 CLI 的全局安装；<br> 2、<code>neo-cmp-cli</code> 1.15.6及以上版本支持此功能。</p></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 交互选择目标产品</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">neo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli-skills</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 指定目标产品（跳过交互）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">neo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli-skills</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codebuddy</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">neo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli-skills</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kiro</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">neo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli-skills</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cursor</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">neo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli-skills</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claudeCode</span></span></code></pre></div><p>执行后，CLI 会将技能包安装到所选产品的 skill 目录下。若目标目录中已存在同名 skill，会以覆盖方式写入。</p><h3 id="支持手动下载和安装" tabindex="-1">支持手动下载和安装 <a class="header-anchor" href="#支持手动下载和安装" aria-label="Permalink to &quot;支持手动下载和安装&quot;">​</a></h3><p>如果网络环境不佳（cli 安装慢）或 电脑上没有安装 Node 环境（安装 cli 依赖 Node 环境），也可通过下载技能包手动安装到 AI 编辑器（CodeBuddy、Kiro、Cursor等）中。</p><h4 id="下载技能包" tabindex="-1">下载技能包 <a class="header-anchor" href="#下载技能包" aria-label="Permalink to &quot;下载技能包&quot;">​</a></h4><ul><li><strong>点击下载</strong>：<a href="/neo-cmp-docs/html/skills.zip">skills.zip</a>。</li></ul><p>技能包内包含以下技能：</p><table tabindex="0"><thead><tr><th>Skill</th><th>作用</th></tr></thead><tbody><tr><td><code>neo-cmp-cli</code></td><td><code>neo</code> 命令行工具技能</td></tr><tr><td><code>neo-cmp-dev</code></td><td>React 16 + TypeScript 自定义组件开发技能</td></tr><tr><td><code>neo-code-review</code></td><td>Neo 平台自定义组件代码审查与规范校验技能</td></tr><tr><td><code>vue-to-react</code></td><td>Vue 组件 / 项目迁移到 React 16 + TypeScript 的语法层技能</td></tr><tr><td><code>frontend-design</code></td><td>前端创意设计技能</td></tr></tbody></table><h4 id="手动安装步骤" tabindex="-1">手动安装步骤 <a class="header-anchor" href="#手动安装步骤" aria-label="Permalink to &quot;手动安装步骤&quot;">​</a></h4><p>根据你使用的 AI 编辑器，将 <code>skills.zip</code> 解压得到的 skill 添加导入到对应的 AI 编辑器（CodeBuddy、Kiro、Cursor等）即可。</p><p>以 CodeBuddy 为例，skill 添加导入步骤如下：</p><ol><li>在「技能」页面，点击右上角的「+ 添加技能」按钮，选择「上传技能」；</li><li>选择 <code>skills.zip</code> 解压得到的 <code>neo-cmp-cli</code> 目录（skills/neo-cmp-cli），点击「确定」；</li><li>重复步骤 1、2 导入 <code>neo-cmp-dev</code>、<code>neo-code-review</code>、<code>vue-to-react</code>、<code>frontend-design</code> 四个 skill。</li></ol><div class="tip custom-block"><p class="custom-block-title">覆盖说明</p><p>若目标目录中已有同名 skill，覆盖式写入即可。</p></div><h2 id="更新技能包" tabindex="-1">更新技能包 <a class="header-anchor" href="#更新技能包" aria-label="Permalink to &quot;更新技能包&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 交互选择目标产品</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">neo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli-skills</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 指定目标产品</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">neo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli-skills</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codebuddy</span></span></code></pre></div><p>更新命令会下载最新技能包，并在选定产品的 skill 目录中覆盖式的更新原有的 skills。</p><h2 id="移除技能包" tabindex="-1">移除技能包 <a class="header-anchor" href="#移除技能包" aria-label="Permalink to &quot;移除技能包&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 交互选择目标产品</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">neo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli-skills</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 指定目标产品</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">neo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cli-skills</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codebuddy</span></span></code></pre></div><p>移除命令会在选定产品的 skill 目录中清理以下 skills：</p><ul><li><code>neo-cmp-cli</code></li><li><code>neo-cmp-dev</code></li><li><code>neo-code-review</code></li><li><code>vue-to-react</code></li><li><code>frontend-design</code></li></ul><div class="tip custom-block"><p class="custom-block-title">关于 frontend-design</p><p><code>remove</code> 命令不会删除 <code>frontend-design</code>，避免影响通用的前端设计类工作流。如需整体清理，可手动删除对应目录。</p></div><h2 id="命令速查" tabindex="-1">命令速查 <a class="header-anchor" href="#命令速查" aria-label="Permalink to &quot;命令速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th><th>参数</th></tr></thead><tbody><tr><td><code>neo add cli-skills</code></td><td>安装「组件开发 Skills」到指定产品的 skill 目录（用户级）</td><td><code>-p</code> / <code>--product</code> 目标产品（<code>codebuddy</code> / <code>kiro</code> / <code>cursor</code> / <code>claudeCode</code>）</td></tr><tr><td><code>neo update cli-skills</code></td><td>更新指定产品下的「组件开发 Skills」（覆盖式 copy <code>neo-cmp-cli</code> / <code>neo-cmp-dev</code> / <code>neo-code-review</code> / <code>vue-to-react</code> / <code>frontend-design</code>）</td><td><code>-p</code> / <code>--product</code> 目标产品</td></tr><tr><td><code>neo remove cli-skills</code></td><td>移除指定产品下的「组件开发 Skills」（清理 <code>neo-cmp-cli</code> / <code>neo-cmp-dev</code> / <code>neo-code-review</code> / <code>vue-to-react</code>）</td><td><code>-p</code> / <code>--product</code> 目标产品</td></tr></tbody></table><h2 id="使用-case" tabindex="-1">使用 Case <a class="header-anchor" href="#使用-case" aria-label="Permalink to &quot;使用 Case&quot;">​</a></h2><p>安装完技能包后，在支持的 AI 编辑器（Kiro / CodeBuddy / Cursor / Claude Code）中，只需用自然语言描述需求，AI 助手会按技能包约定自动匹配对应的 skill，走标准的 Neo 自定义组件开发流程（创建项目 / 组件目录 → 写 <code>index.tsx</code> + <code>model.ts</code> + <code>propsSchema</code> → 事件动作 → 数据源对接 → 样式隔离 → 预览 / 发布）。</p><p>以下是几个典型的使用 case，直接把「Prompt 示例」粘到 AI 对话框里就能跑：</p><h3 id="case-1-客户列表-点击查看详情-pc-端" tabindex="-1">Case 1：客户列表 + 点击查看详情（PC 端） <a class="header-anchor" href="#case-1-客户列表-点击查看详情-pc-端" aria-label="Permalink to &quot;Case 1：客户列表 + 点击查看详情（PC 端）&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">Prompt 示例</p><p>开发一个展示客户列表的自定义组件，支持点击某一行跳转到该客户的详情页。</p></div><p>AI 助手结合 <code>neo-cmp-dev</code> 技能，典型会这么做：</p><ol><li>通过 <code>neo create cmp</code> 在 <code>src/components</code> 下生成组件目录（例如 <code>accountListCmp__c</code>）；</li><li>识别到「客户」对应 Neo 标准实体 <code>Account</code>，并提示通过 <code>xObject.getDesc(&#39;Account&#39;)</code> 或 <code>scripts/fetchEntityDesc.js</code> 查询 <code>Account</code> 的真实字段，避免杜撰字段名；</li><li>在 <code>propsSchema</code> 中暴露「要展示的字段」「每页条数」「是否展示操作列」等属性面板配置项，并默认选择 <code>name</code> / <code>customerType</code> / <code>phone</code> / <code>owner</code> 等已有字段；</li><li>在 <code>index.tsx</code> 中通过 <code>xObject.getData({ apiKey: &#39;Account&#39;, ... })</code> 拉取客户列表，使用平台预置的 PC 版列表组件或 antd <code>Table</code> 渲染；</li><li>为「行点击」定义事件动作（<code>@NeoEvent.click</code>），通过 <code>props.env.ctx</code> 打开标准的客户详情页（路由到 <code>Account</code> 实体详情），无需手写跳转 URL；</li><li>样式写在 <code>style.scss</code> 中，根节点 className 与组件目录名保持一致，交由 CLI 做样式隔离。</li></ol><p>完成后，AI 助手会按 <code>neo-cmp-cli</code> 技能的约定提示：是否需要执行 <code>neo preview</code> 在线预览、<code>neo linkDebug</code> 外链调试，或 <code>neo push cmp</code> 发布到 NeoCRM。</p><h3 id="case-2-h5-版客户列表-点击查看详情" tabindex="-1">Case 2：H5 版客户列表 + 点击查看详情 <a class="header-anchor" href="#case-2-h5-版客户列表-点击查看详情" aria-label="Permalink to &quot;Case 2：H5 版客户列表 + 点击查看详情&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">Prompt 示例</p><p>开发一个 H5 版的客户列表自定义组件，支持点击某一条查看客户详情，使用 H5 端常用的卡片 / 下拉刷新 + 触底加载样式。</p></div><p>AI 助手结合 <code>neo-cmp-dev</code> 技能，相对 Case 1 的差异主要在：</p><ol><li>在 <code>neo create cmp</code> 时通过 <code>-d</code> / <code>--targetDevice</code> 指定目标设备类型为 H5，或使用 <code>neo-h5-cmps</code> 模板起步（在首次初始化项目且用户明确需要 H5 模板时用 <code>neo init -t neo-h5-cmps</code>）；</li><li>优先使用平台预置的 <strong>H5 版列表组件</strong>（参见 <a href="/neo-cmp-docs/html/cmpDocs/H5版列表组件使用说明.html">H5 版 列表组件使用说明</a>），接入 <code>Account</code> 实体数据源，直接获得下拉刷新、触底加载、卡片布局等能力；</li><li>「查看详情」通过 <code>props.env.ctx</code> 调用平台实体详情跳转能力，H5 端会自动走移动端详情页路由；</li><li>样式采用 SCSS + BEM，根节点 className 与组件目录名一致，保证 H5 端的样式隔离。</li></ol><h3 id="case-3-商机列表-分页-新增-删除" tabindex="-1">Case 3：商机列表 + 分页 + 新增 / 删除 <a class="header-anchor" href="#case-3-商机列表-分页-新增-删除" aria-label="Permalink to &quot;Case 3：商机列表 + 分页 + 新增 / 删除&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">Prompt 示例</p><p>开发一个展示商机列表的自定义组件：支持分页展示，支持新增商机和删除商机两种操作。</p></div><p>AI 助手结合 <code>neo-cmp-dev</code> 技能，典型会这么做：</p><ol><li>识别到「商机」对应 Neo 标准实体 <code>Opportunity</code>，先查 <code>Opportunity</code> 已有字段列表（<code>xObject.getDesc</code> 或 <code>scripts/fetchEntityDesc.js</code>），在 <code>propsSchema</code> 中通过 <code>selectFieldsApi</code> 让业务方选要展示的字段；</li><li>在 <code>index.tsx</code> 中调用 <code>xObject.getData({ apiKey: &#39;Opportunity&#39;, pageSize, pageNum, ... })</code> 拉分页数据，并把分页状态（<code>pageNum</code> / <code>pageSize</code> / <code>total</code>）维护在组件 state 中；</li><li>「新增」按钮通过 <code>props.env.ctx</code> 打开 <code>Opportunity</code> 的新建表单页；「删除」按钮调用 <code>xObject.delete({ apiKey: &#39;Opportunity&#39;, ids: [...] })</code>，删除前使用 antd <code>Modal.confirm</code> 做二次确认；</li><li>新增 / 删除成功后，触发定义在 <code>model.ts</code> 中的组件事件（如 <code>onCreated</code> / <code>onDeleted</code>），便于其他组件联动；同时刷新当前分页的数据；</li><li>所有与平台交互的动作均用 <code>@NeoEvent.function</code> / <code>@NeoEvent.click</code> 装饰，确保属性面板「事件动作」可正确识别。</li></ol><h3 id="case-4-基于-jsonplaceholder-的用户信息卡片列表" tabindex="-1">Case 4：基于 jsonplaceholder 的用户信息卡片列表 <a class="header-anchor" href="#case-4-基于-jsonplaceholder-的用户信息卡片列表" aria-label="Permalink to &quot;Case 4：基于 jsonplaceholder 的用户信息卡片列表&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">Prompt 示例</p><p>使用 <a href="https://jsonplaceholder.typicode.com/users" target="_blank" rel="noreferrer">https://jsonplaceholder.typicode.com/users</a> 接口，写一个展示用户信息的卡片列表自定义组件（卡片要包含姓名、邮箱、公司名、地址等字段）。</p></div><p>AI 助手结合 <code>neo-cmp-dev</code> 技能，典型会这么做：</p><ol><li>识别到这是<strong>第三方接口</strong>、不是 Neo 实体，走「自定义 API（通用代理）」场景：通过平台通用代理 <code>/rest/data/v2.0/scripts/api/proxy/forward</code> 转发请求，避免浏览器端跨域与鉴权问题；</li><li>在 <code>propsSchema</code> 中暴露一个「自定义 API 配置项」，默认值指向 <code>https://jsonplaceholder.typicode.com/users</code>，允许业务方在属性面板替换目标接口；</li><li>在 <code>index.tsx</code> 中用 <code>customApi.run(fetchConfig)</code> 发起请求，对返回结果做统一兜底（数组 / <code>{ data: [...] }</code> / <code>{ records: [...] }</code> 等结构都要兼容）；</li><li>使用 antd <code>Card</code> / <code>Row</code> / <code>Col</code> 渲染成卡片网格，卡片内部展示 <code>name</code> / <code>email</code> / <code>company.name</code> / <code>address.city</code> 等字段；<code>Spin</code> 处理加载态、<code>Empty</code> 处理错误与空数据态；</li><li>样式写在 <code>style.scss</code> 中，根节点 className 与组件目录名一致；响应式布局通过 antd 的栅格 <code>xs</code> / <code>sm</code> / <code>md</code> 断点实现。</li></ol><div class="tip custom-block"><p class="custom-block-title">可直接参考的示例</p><p>CLI 自带的 <code>neo-custom-cmp-template</code> 模板中就有一个 <code>customApi__c</code> 组件，用的就是 <code>customApi.run</code> + <code>jsonplaceholder</code> 接口，AI 助手会主动参考这个样例快速落地。</p></div><h2 id="使用反馈" tabindex="-1">使用反馈 <a class="header-anchor" href="#使用反馈" aria-label="Permalink to &quot;使用反馈&quot;">​</a></h2><p>「组件开发 Skills」仍在 Beta 阶段，欢迎在实际开发中持续试用。如遇到以下任一场景，请在 <a href="https://github.com/xsy-neoui/neo-cmp-docs/issues" target="_blank" rel="noreferrer">neo-cmp-docs Issues</a> 提交反馈：</p><ul><li>AI 助手输出的代码不符合 Neo 自定义组件规范；</li><li>某个技能包的指引与当前 CLI / 平台行为存在冲突；</li><li>需要新增某类使用场景的指引或示例；</li><li>希望支持更多 AI 编辑器的 skill 目录。</li></ul>`,60)])])}const u=s(d,[["render",c]]);export{k as __pageData,u as default};
